//pendiente por configurar
import { post } from "../../../backend/routes/routes";
import {
  BotonTema,
  Header2,
  Footer,
  Github,
} from "../reutilizables/componentes";

import { useState, useEffect } from "react";

function AdminRegistros() {
  const [turno, setturno] = useState("");
  const [fecha, setfecha] = useState("");
  const [produccion, setproduccion] = useState([]);
  const [baches, setbaches] = useState([]);

  const handleConsultarRegistro = async () => {
    try {
      const res = await fetch(
        `http://localhost:4000/api/consultarRegistro?turno=${turno}&fecha=${fecha}`,
        {
          method: "GET",
        },
      );

      const data = await res.json();
      const { results, resultsB } = data;
      setproduccion(results);
      setbaches(resultsB);

      if (!res.ok) {
        alert(data.error || "Error al obtener registros");
      }
    } catch {}
  };
  return (
    <div>
      <BotonTema />
      <div id="container">
        <header id="header1">
          <button id="volver" onClick={() => window.history.back()}>
            Volver
          </button>
        </header>
        <Header2 />
        <section id="content">
          <label>
            Turno:
            <select
              id="turno"
              onChange={(e) => setturno(e.target.value)}
              value={turno}
            >
              <option value={""}>-- Seleccione el turno</option>
              <option value={"Turno 1"}>Turno 1</option>
              <option value={"Turno 2"}>Turno 2</option>
            </select>
          </label>
          <label>
            Ingrese la Fecha:
            <input
              type="date"
              placeholder="Ingrese la fecha"
              value={fecha}
              onChange={(e) => setfecha(e.target.value)}
            ></input>
          </label>

          <button id="consultar" className="principales">
            consultar registro por fecha
          </button>

          <div>
            <h4>Detalles de produccion:</h4>
            <p>
              <strong>Turno:</strong>
              {produccion.turno}
            </p>
            <p>
              <strong>Fecha:</strong>
              {produccion.fecha_prod}
            </p>
            <p>
              <strong>Proveedor de rinde:</strong>
              {produccion.proveedor_rinde}
            </p>
            <p>
              <strong>Lote del rinde:</strong>
              {produccion.lote_rinde}
            </p>
            <p>
              <strong>Canecas de rinde utilizadas:</strong>
              {produccion.num_canecas_rinde}
            </p>
            <p>
              <strong>Litros de rinde utilizados:</strong>
              {produccion.litros_caneca_rinde}
            </p>
            <p>
              <strong>Griego descolgado recibido:</strong>
              {produccion.griego_inicio}
            </p>
            <p>
              <strong>Griego agitado recibido:</strong>
              {produccion.agitado_inicio}
            </p>
            <p>
              <strong>Canecas de griego gastadas:</strong>
              {produccion.suma_baches}
            </p>
            <p>
              <strong>Canecas agitadas entregadas:</strong>
              {produccion.agitadas_final}
            </p>
            <p>
              <strong>Canecas descolgadas entregadas:</strong>
              {produccion.descolgadas_final}
            </p>
          </div>

          <button id="borrar" className="secundarios">
            borrar registro
          </button>
        </section>
        <Footer />
      </div>
      <Github />
    </div>
  );
}

export default AdminRegistros;
